BEGIN TRANSACTION;
CREATE TABLE characters (
            name TEXT PRIMARY KEY,
            class TEXT,
            race TEXT,
            faction TEXT,
            guild TEXT,
            level INTEGER,
            equipped_item_level INTEGER,
            xp INTEGER,
            xp_max INTEGER,
            health INTEGER,
            power INTEGER,
            last_login_ms INTEGER,
            portrait_url TEXT
        );
CREATE TABLE gear (
            character_name TEXT,
            slot TEXT,
            item_id INTEGER,
            name TEXT,
            quality TEXT,
            icon_data TEXT,
            tooltip_params TEXT,
            last_detected TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            PRIMARY KEY (character_name, slot, item_id)
        );
CREATE TABLE timeline (
            timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            character_name TEXT,
            class TEXT,
            type TEXT, -- 'item' or 'level_up'
            item_id INTEGER,
            item_name TEXT,
            item_quality TEXT,
            item_icon TEXT,
            level INTEGER
        );
COMMIT;
